import * as path from 'path';
import * as fs from 'fs';
import * as os from 'os';
import { rimraf } from 'rimraf';
import { Dirty } from '../../../../../../../../../../../subject_repositories/node-dirty/lib/dirty/dirty.js';

describe('Dirty drain event handling', () => {
  it('should flush remaining queued items after write stream drain event', (done) => {
    const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), 'dirty-drain-'));
    const dbPath = path.join(tmpDir, 'test.db');
    const db = new Dirty(dbPath);

    db.on('load', () => {
      let callbackCount = 0;
      const totalKeys = 30;

      // Force backpressure: intercept write stream so first write returns false
      const ws = (db as any)._writeStream;
      const origWrite = ws.write.bind(ws);
      let callCount = 0;

      ws.write = (data: any, cb: any) => {
        callCount++;
        if (callCount === 1) {
          origWrite(data, cb);
          return false; // simulate backpressure
        }
        return origWrite(data, cb);
      };

      const timeout = setTimeout(() => {
        done(new Error(`Only ${callbackCount}/${totalKeys} callbacks fired - drain did not trigger flush`));
      }, 3000);

      for (let i = 0; i < totalKeys; i++) {
        db.set(`key${i}`, `val${i}`, () => {
          callbackCount++;
          if (callbackCount === totalKeys) {
            clearTimeout(timeout);
            db.close();
            rimraf(tmpDir).then(() => done()).catch(done);
          }
        });
      }
    });

    db.on('error', (err: Error) => {
      rimraf(tmpDir).catch(() => {});
      done(err);
    });
  });
});
